import React from "react";
import { Component } from "react";
class Message extends Component{
    constructor(){
        super();
        this.state={
            Message:"This has to be Done Properly"
        }
    }
    changeState(){
        this.setState={
            Message:"This is Done Properly"
        }
    }
    render(){
        return(<div>
            <h2>This is Statefull {this.state.Message}</h2>
            <button onClick={()=>this.chan()}>Subscribe now</button>
        </div>)
        
    }
}
export default Message
